query:
SELECT status, COUNT(*) as cnt FROM articles GROUP BY status ORDER BY cnt DESC;

SELECT slug, COUNT(*) as cnt FROM articles WHERE slug IS NOT NULL AND slug != '' GROUP BY slug HAVING COUNT(*) > 1 ORDER BY cnt DESC LIMIT 10;

SELECT LEFT(title, 60) as title_prefix, COUNT(*) as cnt FROM articles GROUP BY LEFT(title, 60) HAVING COUNT(*) > 1 ORDER BY cnt DESC LIMIT 20;

